        quantize_(m, config, filter_fn=lambda x, fqn: True)

        assert m.weight.scale.shape == (B, 1, N), (
            f"unexpected scale shape {m.weight.scale.shape}"
        )

        quantized = m(input)
        sqnr = compute_error(original, quantized)
        self.assertTrue(sqnr > 20)

